const size_t test_example_lottie_approve_size = sizeof(test_example_lottie_approve);
static uint8_t *lottie_buff = NULL;
size_t lottie_mem = LOTTIE_W * LOTTIE_H * 4;

void test_example_lottie_from_data(void)
{
    ESP_LOGI("Lottie", "Before Create");
    lv_obj_t * lottie = lv_lottie_create(lv_screen_active());
    ESP_LOGI("Lottie", "After Create");

#if LV_DRAW_BUF_ALIGN == 4 && LV_DRAW_BUF_STRIDE_ALIGN == 1
    /*If there are no special requirements, just declare a buffer
      x4 because the Lottie is rendered in ARGB8888_PREMULTIPLIED format*/
    ESP_LOGI("Lottie", "Allocating Lottie buffer: %u bytes", (unsigned)lottie_mem);
    ESP_LOGI("Lottie", "Largest free block: %u", heap_caps_get_largest_free_block(MALLOC_CAP_8BIT));

    lottie_buff = heap_caps_malloc(lottie_mem, MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT);
    assert(lottie_buff != NULL);
    memset(lottie_buff, 0xAA, lottie_mem);

    lv_lottie_set_buffer(lottie, LOTTIE_W, LOTTIE_H, lottie_buff);
    ESP_LOGI("Lottie", "After Buffer Set");
#endif
    
    ESP_LOGI("Lottie", "Size=%u\n", (unsigned)test_example_lottie_approve_size);
    ESP_LOGI("Lottie", "Free heap before: %u\n", heap_caps_get_free_size(MALLOC_CAP_8BIT));
    ESP_LOGI("Lottie", "Before lottie: %u\n", uxTaskGetStackHighWaterMark(NULL));
    ESP_LOGI("Lottie","Largest block before: %u\n", heap_caps_get_largest_free_block(MALLOC_CAP_8BIT));
    lv_lottie_set_src_data(lottie, test_example_lottie_approve, test_example_lottie_approve_size);
    ESP_LOGI("Lottie", "After Set Src");
    ESP_LOGI("Lottie", "After Lottie: %u\n", uxTaskGetStackHighWaterMark(NULL));
    ESP_LOGI("Lottie", "Free heap after: %u\n", heap_caps_get_free_size(MALLOC_CAP_8BIT));

    lv_obj_set_size(lottie, LOTTIE_W, LOTTIE_H);
    lv_obj_center(lottie);
}

void test_ui_init(lv_disp_t *disp)
{
    #if 1
    test_example_lottie_from_data();
    #else
    static lv_style_t style_label_bg;

    static bool inited = false;

    if(!inited) {
        lv_style_init(&style_label_bg);
        lv_style_set_bg_opa(&style_label_bg, (255 * 100 / 100));
        lv_style_set_radius(&style_label_bg, 6);

        inited = true;
    }

    lv_obj_t * screen = lv_screen_active();
    lv_obj_set_flex_flow(screen, LV_FLEX_FLOW_COLUMN);
    lv_obj_set_style_flex_main_place(screen, LV_FLEX_ALIGN_CENTER, 0);
    lv_obj_set_style_flex_cross_place(screen, LV_FLEX_ALIGN_CENTER, 0);
    lv_obj_set_style_flex_track_place(screen, LV_FLEX_ALIGN_CENTER, 0);
    lv_obj_set_style_pad_row(screen, 16, 0);

    /* Wrap mode example */
    lv_obj_t * label_1 = lv_label_create(screen);
    lv_obj_set_width(label_1, 170);
    lv_label_set_long_mode(label_1, LV_LABEL_LONG_MODE_WRAP);
    lv_obj_set_style_bg_color(label_1, lv_color_hex(0xd6eaf8), 0);
    lv_label_set_text(label_1, "Wrap keeps all text visible by splitting long lines into multiple rows.");
    lv_obj_add_style(label_1, &style_label_bg, 0);

    /* Dots mode example */
    lv_obj_t * label_2 = lv_label_create(screen);
    lv_obj_set_size(label_2, 170, 32);
    lv_label_set_long_mode(label_2, LV_LABEL_LONG_MODE_DOTS);
    lv_obj_set_style_bg_color(label_2, lv_color_hex(0xd5f5e3), 0);
    lv_label_set_text(label_2, "Dots shortens overflowing text and replaces the tail with '...'");
    lv_obj_add_style(label_2, &style_label_bg, 0);
    #endif
}